import React, { useRef } from 'react';
import { motion, useScroll, useTransform, useSpring } from 'framer-motion';
import { Check, Shield, Award, Lock, Star, ChevronDown } from 'lucide-react';
import { cn } from '@/lib/utils';

// --- Types & Constants ---

interface Testimonial {
  id: number;
  quote: string;
  author: string;
  role: string;
  location: string;
}
interface CurriculumItem {
  module: string;
  instructor: string;
  time: string;
  tag: string;
}
interface CurriculumDay {
  title: string;
  dayLabel: string;
  items: CurriculumItem[];
}
const TESTIMONIALS: Testimonial[] = [{
  id: 1,
  quote: "This masterclass completely transformed how I think about bread. Chef Elena's sourdough module alone was worth every penny.",
  author: "M.T.",
  role: "Home Baker",
  location: "London"
}, {
  id: 2,
  quote: "I went from nervous beginner to running my own pop-up bakery in six months. The curriculum is genuinely world-class.",
  author: "R.K.",
  role: "Culinary Graduate",
  location: "New York"
}, {
  id: 3,
  quote: "The fermentation session changed everything. I finally understand the science behind the craft.",
  author: "S.B.",
  role: "Pastry Chef",
  location: "Paris"
}];
const CURRICULUM: CurriculumDay[] = [{
  title: 'Foundations of Bread',
  dayLabel: 'DAY 01',
  items: [{
    module: 'Sourdough Starter Science',
    instructor: 'Chef Elena Russo',
    time: '9:00–10:30 AM',
    tag: 'Science'
  }, {
    module: 'Flour Selection and Hydration',
    instructor: 'Chef Marcus Webb',
    time: '11:00–12:30 PM',
    tag: 'Technique'
  }, {
    module: 'Fermentation Fundamentals',
    instructor: 'Chef Elena Russo',
    time: '2:00–3:30 PM',
    tag: 'Science'
  }, {
    module: 'Shaping and Scoring',
    instructor: 'Chef James Allard',
    time: '4:00–5:00 PM',
    tag: 'Craft'
  }]
}, {
  title: 'Advanced Techniques',
  dayLabel: 'DAY 02',
  items: [{
    module: 'Enriched Doughs and Brioche',
    instructor: 'Chef Marcus Webb',
    time: '9:00–10:30 AM',
    tag: 'Technique'
  }, {
    module: 'Laminated Pastry Foundations',
    instructor: 'Chef James Allard',
    time: '11:00–12:30 PM',
    tag: 'Craft'
  }, {
    module: 'Oven Dynamics and Steam',
    instructor: 'Chef Elena Russo',
    time: '2:00–3:30 PM',
    tag: 'Science'
  }, {
    module: 'Crust Colour and Texture',
    instructor: 'Chef Marcus Webb',
    time: '4:00–5:00 PM',
    tag: 'Craft'
  }]
}, {
  title: 'Mastery and Refinement',
  dayLabel: 'DAY 03',
  items: [{
    module: 'Regional Bread Traditions',
    instructor: 'Chef James Allard',
    time: '9:00–10:30 AM',
    tag: 'Culture'
  }, {
    module: 'Menu Development',
    instructor: 'Chef Elena Russo',
    time: '11:00–12:30 PM',
    tag: 'Business'
  }, {
    module: 'Live Critique and Feedback',
    instructor: 'All Instructors',
    time: '2:00–4:00 PM',
    tag: 'Workshop'
  }, {
    module: 'Final Showcase and Certification',
    instructor: 'All Instructors',
    time: '4:00–5:30 PM',
    tag: 'Milestone'
  }]
}];
const TAG_COLORS: Record<string, string> = {
  Science: 'bg-[#EEF1FB] text-[#1B2A8B]',
  Technique: 'bg-[#FDF3E3] text-[#8B5E1B]',
  Craft: 'bg-[#F0F9F2] text-[#1B6B2A]',
  Culture: 'bg-[#F9EEF8] text-[#7B1B8B]',
  Business: 'bg-[#FEF4F4] text-[#8B1B1B]',
  Workshop: 'bg-[#EEF9FB] text-[#1B708B]',
  Milestone: 'bg-[#1B2A8B] text-white'
};

// --- Sub-components ---

const SectionEyebrow = ({
  children,
  className,
  light = false
}: {
  children: React.ReactNode;
  className?: string;
  light?: boolean;
}) => <span className={cn('block uppercase tracking-[0.4em] text-[11px] font-bold mb-6', light ? 'text-white/60' : 'text-[#1B2A8B]', className)}>
    {children}
  </span>;
const SectionHeadline = ({
  children,
  className,
  light = false
}: {
  children: React.ReactNode;
  className?: string;
  light?: boolean;
}) => <h2 className={cn('font-black uppercase leading-[0.9] tracking-tight mb-8', light ? 'text-white' : 'text-[#1B2A8B]', className)}>
    {children}
  </h2>;
const PrimaryButton = ({
  children,
  className,
  variant = 'primary'
}: {
  children: React.ReactNode;
  className?: string;
  variant?: 'primary' | 'white';
}) => <button className={cn('inline-flex items-center justify-center px-10 py-5 font-black uppercase tracking-widest text-[14px] transition-all active:scale-95 cursor-pointer', variant === 'primary' ? 'bg-[#1B2A8B] text-white hover:bg-[#1B2A8B]/90' : 'bg-white text-[#1B2A8B] hover:bg-white/90', className)}>
    {children}
  </button>;

// --- Hero: Full-bleed image with centered floating editorial text ---

const Hero = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const {
    scrollYProgress
  } = useScroll({
    target: containerRef,
    offset: ['start start', 'end start']
  });
  const imgY = useTransform(scrollYProgress, [0, 1], ['0%', '20%']);
  const textY = useTransform(scrollYProgress, [0, 1], ['0%', '12%']);
  const opacity = useTransform(scrollYProgress, [0, 0.7], [1, 0]);
  return <section ref={containerRef} className="relative w-full h-screen min-h-[700px] overflow-hidden flex items-center justify-center">
      {/* Full-bleed parallax image */}
      <motion.div className="w-full h-full" style={{
      y: imgY
    }}>
        <img src="https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&q=80&w=1800" alt="Artisan bread close-up" className="w-full h-full object-cover" style={{
        filter: 'brightness(0.45) grayscale(0.3)'
      }} />
      </motion.div>

      {/* Centered editorial headline */}
      <motion.div style={{
      y: textY,
      opacity
    }} className="absolute inset-0 flex flex-col items-center justify-center text-center px-6">
        <motion.span initial={{
        opacity: 0,
        y: 20
      }} animate={{
        opacity: 1,
        y: 0
      }} transition={{
        duration: 0.9,
        delay: 0.2
      }} className="block uppercase tracking-[0.6em] text-[11px] font-bold text-white/60 mb-8">
          THE ART OF BREAD
        </motion.span>

        <motion.h1 initial={{
        opacity: 0,
        y: 40
      }} animate={{
        opacity: 1,
        y: 0
      }} transition={{
        duration: 1,
        delay: 0.35
      }} className="text-white font-black uppercase text-[64px] md:text-[110px] lg:text-[130px] leading-[0.85] tracking-tight max-w-[1100px]">
          Master the Craft of Artisan Baking
        </motion.h1>

        <motion.p initial={{
        opacity: 0,
        y: 30
      }} animate={{
        opacity: 1,
        y: 0
      }} transition={{
        duration: 0.9,
        delay: 0.6
      }} className="text-white/70 text-[17px] md:text-[20px] leading-relaxed max-w-[520px] mt-10 mb-12">
          A world-class culinary journey from foundational science to the final perfect crust.
        </motion.p>

        <motion.div initial={{
        opacity: 0,
        y: 20
      }} animate={{
        opacity: 1,
        y: 0
      }} transition={{
        duration: 0.8,
        delay: 0.8
      }}>
          <PrimaryButton variant="white" className="shadow-2xl">ENROLL NOW</PrimaryButton>
        </motion.div>
      </motion.div>

      {/* Floating editorial details — bottom-left */}
      <motion.div style={{
      opacity
    }} initial={{
      opacity: 0
    }} animate={{
      opacity: 1
    }} transition={{
      duration: 1,
      delay: 1.1
    }} className="absolute bottom-12 left-8 md:left-14 flex flex-col gap-1">
        <span className="text-white/40 text-[10px] uppercase tracking-[0.4em] font-bold">Cohort</span>
        <span className="text-white font-black text-[14px] uppercase tracking-widest">2025 — Spring</span>
      </motion.div>

      {/* Floating editorial details — bottom-right */}
      <motion.div style={{
      opacity
    }} initial={{
      opacity: 0
    }} animate={{
      opacity: 1
    }} transition={{
      duration: 1,
      delay: 1.1
    }} className="absolute bottom-12 right-8 md:right-14 flex flex-col items-end gap-1">
        <span className="text-white/40 text-[10px] uppercase tracking-[0.4em] font-bold">Seats</span>
        <span className="text-white font-black text-[14px] uppercase tracking-widest">50 Available</span>
      </motion.div>

      {/* Vertical scroll indicator */}
      <motion.div style={{
      opacity
    }} className="absolute bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-3">
        <span className="text-white/40 text-[9px] uppercase tracking-[0.5em]">Scroll</span>
        <motion.div animate={{
        y: [0, 8, 0]
      }} transition={{
        duration: 1.5,
        repeat: Infinity,
        ease: 'easeInOut'
      }} className="w-[1px] h-8 bg-white/30" />
      </motion.div>
    </section>;
};
const MarqueeTicker = () => {
  const phrases = ['ARTISAN BREAD TECHNIQUES', 'WORLD-CLASS INSTRUCTORS', 'LIMITED COHORT SEATS', 'HANDS-ON TRAINING', 'CERTIFICATION INCLUDED', 'SOURDOUGH MASTERY', 'ENROLL NOW'];
  return <div className="w-full h-[90px] bg-[#1B2A8B] flex items-center overflow-hidden border-y border-white/10">
      <motion.div className="flex whitespace-nowrap gap-12" animate={{
      x: [0, -1000]
    }} transition={{
      duration: 30,
      repeat: Infinity,
      ease: 'linear'
    }}>
        {[...Array(4)].map((_, i) => <div key={i} className="flex items-center gap-12">
            {phrases.map((phrase, idx) => <div key={idx} className="flex items-center gap-12">
                <span className="text-white font-black uppercase text-[18px] tracking-widest">{phrase}</span>
                <span className="text-white text-[10px]">◆</span>
              </div>)}
          </div>)}
      </motion.div>
    </div>;
};
const FeaturedIn = () => {
  const publications = ['THE NEW YORK TIMES', 'BON APPETIT', 'FOOD AND WINE', 'THE GUARDIAN', 'SAVEUR', 'EATER'];
  return <section className="w-full h-auto py-16 md:h-[280px] bg-white flex flex-col items-center justify-center border-b border-[#E8E8E8]">
      <SectionEyebrow className="mb-10 text-center !tracking-[0.6em] !text-[#AAAAAA]">AS FEATURED IN</SectionEyebrow>
      <div className="flex flex-wrap justify-center items-center gap-x-12 gap-y-8 px-6">
        {publications.map(pub => <span key={pub} className="text-[#CCCCCC] hover:text-[#333] transition-colors font-black uppercase text-[18px] md:text-[22px] tracking-tight cursor-default">
            {pub}
          </span>)}
      </div>
    </section>;
};
const AwarenessStatement = () => {
  return <section className="w-full min-h-[90vh] bg-[#1B2A8B] flex flex-col items-center justify-center text-center px-6 py-24">
      <motion.div initial={{
      opacity: 0,
      y: 30
    }} whileInView={{
      opacity: 1,
      y: 0
    }} transition={{
      duration: 1,
      ease: 'easeOut'
    }} viewport={{
      once: true
    }}>
        <h2 className="text-white font-black uppercase text-[60px] md:text-[110px] leading-[0.9] tracking-tight max-w-[1000px] mb-12">
          MOST PEOPLE <br /> BAKE BREAD. <br /> FEW TRULY <br /> UNDERSTAND IT.
        </h2>
        <div className="space-y-2 max-w-[600px] mx-auto">
          <p className="text-white/80 text-[18px] md:text-[20px] leading-relaxed">
            Our masterclass teaches you the science, craft, and intuition
          </p>
          <p className="text-white/80 text-[18px] md:text-[20px] leading-relaxed">
            behind every perfect loaf.
          </p>
        </div>
      </motion.div>
    </section>;
};

// --- Curriculum: Masonry grid of cards ---

const Curriculum = () => {
  return <section className="w-full bg-white py-24 px-6 md:px-[80px]">
      <div className="max-w-[1240px] mx-auto">
        <div className="mb-16">
          <SectionEyebrow>THE CURRICULUM</SectionEyebrow>
          <SectionHeadline className="text-[64px] md:text-[84px] mb-4">WHAT YOU WILL LEARN</SectionHeadline>
          <p className="text-[#4A4A4A] text-[18px]">An intensive roadmap to professional-grade baking.</p>
        </div>

        {CURRICULUM.map((day, dayIdx) => <div key={day.dayLabel} className="mb-20">
            {/* Day header strip */}
            <div className="flex items-baseline gap-6 mb-8 border-b border-[#E8E8E8] pb-5">
              <span className="text-[#1B2A8B] font-black uppercase text-[11px] tracking-[0.4em]">{day.dayLabel}</span>
              <span className="text-[#1B2A8B] font-black uppercase text-[28px] md:text-[36px] leading-none tracking-tight">
                {day.title}
              </span>
            </div>

            {/* Masonry-style grid */}
            <div className="columns-1 sm:columns-2 lg:columns-4 gap-4 space-y-4">
              {day.items.map((item, itemIdx) => {
            const isHighlighted = dayIdx === 2 && itemIdx === 3;
            const isWide = itemIdx % 3 === 1;
            return <motion.div key={`${dayIdx}-${itemIdx}`} initial={{
              opacity: 0,
              y: 24
            }} whileInView={{
              opacity: 1,
              y: 0
            }} transition={{
              duration: 0.55,
              delay: itemIdx * 0.08
            }} viewport={{
              once: true,
              margin: '-60px'
            }} className={cn('break-inside-avoid border p-7 flex flex-col gap-4 group cursor-default transition-all duration-300', isHighlighted ? 'bg-[#1B2A8B] border-[#1B2A8B]' : 'bg-white border-[#E8E8E8] hover:border-[#1B2A8B]', isWide ? 'pb-10' : '')}>
                    {/* Tag */}
                    <div className="flex items-center justify-between">
                      <span className={cn('inline-block text-[10px] font-black uppercase tracking-[0.3em] px-3 py-1.5', isHighlighted ? 'bg-white/20 text-white' : TAG_COLORS[item.tag] ?? 'bg-gray-100 text-gray-600')}>
                        {item.tag}
                      </span>
                      <span className={cn('text-[11px] font-mono', isHighlighted ? 'text-white/50' : 'text-[#AAAAAA]')}>
                        {String(itemIdx + 1).padStart(2, '0')}
                      </span>
                    </div>

                    {/* Module name */}
                    <h3 className={cn('font-black text-[17px] leading-tight tracking-tight', isHighlighted ? 'text-white' : 'text-[#1B2A8B]')}>
                      {item.module}
                    </h3>

                    {/* Divider */}
                    <div className={cn('h-[1px] w-full', isHighlighted ? 'bg-white/20' : 'bg-[#EEEEEE]')} />

                    {/* Meta */}
                    <div className="flex flex-col gap-1">
                      <span className={cn('text-[13px]', isHighlighted ? 'text-white/70' : 'text-[#4A4A4A]')}>
                        {item.instructor}
                      </span>
                      <span className={cn('text-[12px] font-mono', isHighlighted ? 'text-white/40' : 'text-[#AAAAAA]')}>
                        {item.time}
                      </span>
                    </div>
                  </motion.div>;
          })}
            </div>
          </div>)}
      </div>
    </section>;
};
const Testimonials = () => {
  return <section className="w-full bg-white py-32 px-6">
      <div className="max-w-[1240px] mx-auto text-center mb-20">
        <SectionEyebrow className="justify-center">TESTIMONIALS</SectionEyebrow>
        <SectionHeadline className="text-[52px] md:text-[64px]">WHAT OUR STUDENTS SAY</SectionHeadline>
      </div>

      <div className="max-w-[1240px] mx-auto grid grid-cols-1 md:grid-cols-3 gap-6">
        {TESTIMONIALS.map(t => <div key={t.id} className="bg-white border border-[#E8E8E8] p-10 flex flex-col justify-between hover:shadow-xl transition-all duration-500">
            <div>
              <div className="flex gap-1 mb-8">
                {[...Array(5)].map((_, i) => <Star key={i} size={18} fill="#F5A623" color="#F5A623" />)}
              </div>
              <p className="text-[#4A4A4A] text-[18px] leading-relaxed italic mb-10">
                <span>"{t.quote}"</span>
              </p>
            </div>
            <div className="pt-8 border-t border-[#E8E8E8] flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-[#1B2A8B] flex items-center justify-center text-white font-black text-[14px]">
                <span>{t.author}</span>
              </div>
              <div className="flex flex-col">
                <span className="text-[#1B2A8B] font-black text-[14px] uppercase tracking-wider">{t.role}</span>
                <span className="text-[#AAAAAA] text-[12px] uppercase tracking-widest">{t.location}</span>
              </div>
            </div>
          </div>)}
      </div>
    </section>;
};

// --- Instructor: Parallax overlapping layout ---

const InstructorBio = () => {
  const sectionRef = useRef<HTMLDivElement>(null);
  const {
    scrollYProgress
  } = useScroll({
    target: sectionRef,
    offset: ['start end', 'end start']
  });
  const imgScale = useTransform(scrollYProgress, [0, 1], [1.08, 1.0]);
  const imgY = useTransform(scrollYProgress, [0, 1], ['4%', '-4%']);
  const textY = useTransform(scrollYProgress, [0, 1], ['6%', '-6%']);
  const cardY = useTransform(scrollYProgress, [0, 1], ['10%', '-2%']);
  return <section ref={sectionRef} className="relative w-full bg-white overflow-hidden py-0" style={{
    minHeight: '90vh'
  }}>
      <div className="max-w-[1440px] mx-auto flex flex-col md:flex-row items-stretch">
        {/* Left: Parallax image, bleeds slightly out */}
        <div className="w-full md:w-[48%] relative overflow-hidden" style={{
        minHeight: '600px'
      }}>
          <motion.div style={{
          scale: imgScale,
          y: imgY
        }} className="w-full h-full">
            <img src="https://images.unsplash.com/photo-1583394838336-acd977736f90?auto=format&fit=crop&q=80&w=1200" alt="Chef Elena Russo" className="w-full h-full object-cover grayscale" style={{
            minHeight: '600px'
          }} />
          </motion.div>

          {/* Overlapping stat badge — anchored to image bottom-right, floating over text column */}
          <motion.div style={{
          y: cardY
        }} className="absolute -bottom-8 -right-8 md:-right-16 bg-[#1B2A8B] text-white px-8 py-8 z-20 shadow-2xl">
            <span className="block font-black text-[56px] leading-none tracking-tight">18+</span>
            <span className="block text-white/60 font-bold text-[11px] uppercase tracking-[0.3em] mt-1">Years of Mastery</span>
          </motion.div>
        </div>

        {/* Right: Editorial text content, parallax offset */}
        <motion.div style={{
        y: textY
      }} className="w-full md:w-[52%] bg-white flex flex-col justify-center px-8 md:px-20 pt-24 pb-24 md:pt-32 md:pb-32 relative z-10">
          <SectionEyebrow>LEAD INSTRUCTOR</SectionEyebrow>
          <SectionHeadline className="text-[48px] md:text-[72px]">CHEF ELENA RUSSO</SectionHeadline>

          <div className="space-y-8 mb-16 max-w-[560px]">
            <p className="text-[#4A4A4A] text-[17px] leading-relaxed pl-8 border-l-4 border-[#1B2A8B]">
              Trained at the prestigious Ferrandi Paris and having led artisanal programs across Europe,
              Elena Russo brings nearly two decades of deep-rooted expertise to the kitchen.
            </p>
            <p className="text-[#4A4A4A] text-[17px] leading-relaxed pl-8 border-l-4 border-[#1B2A8B]">
              Her philosophy centers on the marriage of ancient techniques and modern science—understanding
              the microscopic dance of yeast as clearly as the rhythmic motion of kneading.
            </p>
            <p className="text-[#4A4A4A] text-[17px] leading-relaxed pl-8 border-l-4 border-[#1B2A8B]">
              Elena's teaching style is rigorous yet intuitive, designed to move students past following
              recipes into a state of true culinary fluency.
            </p>
          </div>

          {/* Credential stats row */}
          <div className="flex flex-wrap gap-4">
            <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-6 text-center">
              <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-2">12-YR</span>
              <span className="block text-[#1B2A8B] font-bold text-[11px] uppercase tracking-widest">Starter Age</span>
            </div>
            <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-6 text-center">
              <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-2">MASTER</span>
              <span className="block text-[#1B2A8B] font-bold text-[11px] uppercase tracking-widest">Boulanger Level</span>
            </div>
            <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-6 text-center">
              <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-2">40+</span>
              <span className="block text-[#1B2A8B] font-bold text-[11px] uppercase tracking-widest">Countries</span>
            </div>
          </div>
        </motion.div>
      </div>
    </section>;
};
const TrustSection = () => {
  const stats = [{
    value: '2,400+',
    label: 'STUDENTS ENROLLED',
    desc: 'Across 40+ countries'
  }, {
    value: '97%',
    label: 'COMPLETION RATE',
    desc: 'Industry-leading retention'
  }, {
    value: '18+',
    label: 'YEARS EXPERTISE',
    desc: 'Combined instructor experience'
  }, {
    value: '4.9',
    label: 'AVERAGE RATING',
    desc: 'From 1,200+ reviews'
  }];
  return <section className="w-full bg-[#F7F7F9] py-32 px-6">
      <div className="max-w-[1240px] mx-auto">
        <SectionEyebrow className="text-center mb-16">WHY STUDENTS TRUST US</SectionEyebrow>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-y-12">
          {stats.map((stat, idx) => <div key={stat.label} className={cn('px-8 text-center', idx !== stats.length - 1 ? 'md:border-r border-[#E0E0E0]' : '')}>
              <span className="block text-[#1B2A8B] font-black text-[48px] md:text-[64px] leading-tight mb-2 tracking-tight">
                {stat.value}
              </span>
              <span className="block text-[#4A4A4A] font-black text-[12px] uppercase tracking-widest mb-1">
                {stat.label}
              </span>
              <span className="block text-[#AAAAAA] text-[13px]">{stat.desc}</span>
            </div>)}
        </div>

        <div className="mt-24 flex flex-col md:flex-row items-center justify-center gap-12 border-t border-[#E0E0E0] pt-16">
          <div className="flex items-center gap-4 group">
            <div className="w-12 h-12 bg-white flex items-center justify-center border border-[#E0E0E0] group-hover:border-[#1B2A8B] transition-colors">
              <Shield className="text-[#1B2A8B]" size={20} />
            </div>
            <span className="text-[#4A4A4A] font-bold text-[13px] uppercase tracking-wider">30-Day Money-Back Guarantee</span>
